import re
import sys

def drop_cap(s):
    pattern = r'([a-zA-Z]+)'
    def replace(match):
        word = match.group(1)
        if len(word) > 2:
            return word[0].upper() + word[1:].lower()
        else:
            return word
    return re.sub(pattern, replace, s)

