print(result)

def possibles(c):
    oc = ord(c)
    if c == 'a':
        return [oc + 1]
    elif c == 'z':
        return [oc - 1]
    else:
        return [oc - 1, oc + 1]

def solve(st):
    n = len(st)
    if n <= 1:
        return True  # trivial palindrome
    for i in range(n // 2):
        left = possibles(st[i])
        right = possibles(st[n - 1 - i])
        if not (set(left) & set(right)):  # empty intersection → impossible
            return False
    return True

st = input().strip()
print(solve(st))

