def is_possible(string1, string2):
    if len(string1) != len(string2):
        return False
    # Use dicts instead of arrays (per plan alternative): handles any chars, no index errors
    forward = {}
    reverse = {}
    for c1, c2 in zip(string1, string2):
        # Correction 1: dict lookup with get() or 'in' check (equivalent to array but safer)
        if c1 in forward:
            if forward[c1] != c2:
                return False
        else:
            forward[c1] = c2
        # Correction 2: reverse check/set similarly with dict
        if c2 in reverse:
            if reverse[c2] != c1:
                return False
        else:
            reverse[c2] = c1
    return True

