def alphabet_war(fight):
    if not fight:
        return "Let's fight again!"
    left_power = {'w': 4, 'p': 3, 'b': 2, 's': 1}
    right_power = {'m': 4, 'q': 3, 'd': 2, 'z': 1}
    destroyed = [False] * len(fight)
    for i in range(len(fight)):
        if fight[i] == '*':
            destroyed[i] = True
            if i - 1 >= 0:
                destroyed[i - 1] = True
            if i + 1 < len(fight):
                destroyed[i + 1] = True
    left_score = 0
    right_score = 0
    for i in range(len(fight)):
        if not destroyed[i]:
            if fight[i] in left_power:
                left_score += left_power[fight[i]]
            elif fight[i] in right_power:
                right_score += right_power[fight[i]]
    if left_score > right_score:
        return "Left side wins!"
    elif right_score > left_score:
        return "Right side wins!"
    else:
        return "Let's fight again!"

fight = input().strip()
print(alphabet_war(fight))

import math

def _factorize(n):
    if n == 1:
        return [1], [1], [1]
    all_factors = []
    factors = {}
    while n % 2 == 0:
        all_factors.append(2)
        factors[2] = factors.get(2, 0) + 1
        n //= 2
    i = 3
    while i <= math.isqrt(n):
        while n % i == 0:
            all_factors.append(i)
            factors[i] = factors.get(i, 0) + 1
            n //= i
        i += 2
    if n > 1:
        all_factors.append(n)
        factors[n] = factors.get(n, 0) + 1
    primes = sorted(factors.keys())  # Ensure ascending order
    counts = [factors[p] for p in primes]
    return all_factors, primes, counts

def getAllPrimeFactors(n):
    if not isinstance(n, (int, float)):
        return '[]'  # Correction: return str for test framework
    try:
        ni = int(n)
    except (ValueError, OverflowError):
        return '[]'  # Correction: return str
    if isinstance(n, float) and n != ni:
        return '[]'  # Correction: return str
    if ni < 1:
        return '[]'  # Correction: return str
    all_f, _, _ = _factorize(ni)
    return repr(all_f)  # Correction: return repr(list) str matching print(list) output

def getUniquePrimeFactorsWithCount(n):
    if not isinstance(n, (int, float)):
        return repr([[], []])  # Correction: return str repr of expected
    try:
        ni = int(n)
    except (ValueError, OverflowError):
        return repr([[], []])  # Correction: return str
    if isinstance(n, float) and n != ni:
        return repr([[], []])  # Correction: return str
    if ni < 1:
        return repr([[], []])  # Correction: return str
    _, primes, counts = _factorize(ni)
    return repr([primes, counts])  # Correction: return repr for nested list

def getUniquePrimeFactorsWithProducts(n):
    if not isinstance(n, (int, float)):
        return '[]'  # Correction: return str
    try:
        ni = int(n)
    except (ValueError, OverflowError):
        return '[]'  # Correction: return str
    if isinstance(n, float) and n != ni:
        return '[]'  # Correction: return str
    if ni < 1:
        return '[]'  # Correction: return str
    _, primes, counts = _factorize(ni)
    products = [p ** c for p, c in zip(primes, counts)]
    return repr(products)  # Correction: return repr(list) str

