def transform_string(s):
    a = ord('a')
    vowels = set('aeiou')
    exceptions = {'c': -1, 'o': -1, 'd': -3, 'e': -4}
    revert_set = set('code')
    result = []
    for char in s:
        idx = ord(char) - a
        if char in exceptions:
            shift = exceptions[char]
        elif char in vowels:
            shift = -5
        else:
            shift = 9
        new_idx = (idx + shift + 26) % 26
        new_char = chr(new_idx + a)
        if new_char in revert_set:
            result.append(char)
        else:
            result.append(new_char)
    return ''.join(result)

