def fix_yellow(color: str) -> str:
    yellow_mapping = {
        'gold': 'ForestGreen',
        'khaki': 'LimeGreen',
        'lemonchiffon': 'PaleGreen',
        'lightgoldenrodyellow': 'SpringGreen',
        'lightyellow': 'MintCream',
        'palegoldenrod': 'LightGreen',
        'yellow': 'Lime'
    }

    if color.startswith('#') and len(color) == 7:
        r_hex = color[1:3]
        g_hex = color[3:5]
        b_hex = color[5:7]
        try:
            r = int(r_hex, 16)
            g = int(g_hex, 16)
            b = int(b_hex, 16)
        except ValueError:
            return color

        if r > b and g > b:
            vals = sorted([r, g, b], reverse=True)
            new_r = vals[2]
            new_g = vals[0]
            new_b = vals[1]
            hex_digits = color[1:]
            use_upper = any(c.isupper() for c in hex_digits if c.isalpha())
            if use_upper:
                return f'#{new_r:02X}{new_g:02X}{new_b:02X}'
            else:
                return f'#{new_r:02x}{new_g:02x}{new_b:02x}'
        else:
            return color
    else:
        lower_color = color.lower()
        if lower_color in yellow_mapping:
            return yellow_mapping[lower_color]
        else:
            return color

