def tiyFizzBuzz(s: str) -> str:
    upper_vowels = set('AEIOU')
    lower_vowels = set('aeiou')
    result = []
    for char in s:
        if not char.isalpha():
            result.append(char)
        elif char.isupper():
            if char in upper_vowels:
                result.append("Iron Yard")
            else:
                result.append("Iron")
        else:
            if char in lower_vowels:
                result.append("Yard")
            else:
                result.append(char)
    return ''.join(result)

