def is_increasing(seq):
    for i in range(1, len(seq)):
        if seq[i] <= seq[i - 1]:
            return False
    return True

def can_make_increasing(sequence):
    n = len(sequence)
    if n <= 1:
        return True
    if is_increasing(sequence):
        return True
    for skip in range(n):
        good = True
        i = 0
        if i == skip:
            i += 1
        if i == n:
            break
        prev = sequence[i]
        i += 1
        while i < n:
            if i == skip:
                i += 1
                continue
            curr = sequence[i]
            if curr <= prev:
                good = False
                break
            prev = curr
            i += 1
        if good:
            return True
    return False

