def factors(n):
    if not isinstance(n, int) or n < 1:
        return -1  # Return int -1 for invalid, as specified
    fac = []
    i = 1
    while i * i <= n:
        if n % i == 0:
            fac.append(i)
            if i != n // i:
                fac.append(n // i)
        i += 1
    fac.sort(reverse=True)
    return fac  # Return list of factors in descending order

