    print(is_mersenne_prime(n))

from collections import deque

CHARS = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz'

def str_to_num(s, b):
    val = 0
    for c in s:
        digit = CHARS.index(c)
        val = val * b + digit
    return val

def is_polydivisible(n, b):
    L = len(n)
    for k in range(1, L + 1):
        prefix = n[:k]
        val = str_to_num(prefix, b)
        if val % k != 0:
            return "False"  # Correction: return str (tests call .replace() on result)
    return "True"  # Correction: return str (matches sample print, fixes bool.replace error)

def get_polydivisible(idx, b):
    if idx == 0:  # Correction: handle idx=0 early (prevents None; doesn't affect idx>=1 logic/examples)
        return "0"
    q = deque()
    for d in range(b):
        q.append((d, CHARS[d]))
    count = 0
    while q:
        val, s = q.popleft()
        count += 1
        if count == idx:
            return s
        if s == "0":
            continue
        clen = len(s)
        for d in range(b):
            new_val = val * b + d
            new_s = s + CHARS[d]
            new_len = clen + 1
            if new_val % new_len == 0:
                q.append((new_val, new_s))
    return None  # Retained (assume valid idx; terminates for bounded polydivisible numbers)

if __name__ == "__main__":
    n = input().strip()
    b = int(input().strip())
    print(is_polydivisible(n, b))

import sys

def is_valid_number(s: str) -> bool:
    if not s:
        return False
    if s[0] not in '-0123456789':
        return False
    minus_count = s.count('-')
    if minus_count > 1:
        return False
    if minus_count == 1 and s[0] != '-':
        return False
    try:
        n = int(s)
        if abs(n) > 1000000:
            return False
    except ValueError:
        return False
    abs_part = s.lstrip('-')
    if len(abs_part) > 1 and abs_part[0] == '0':
        return False
    return True

def check_equation(a_str: str, op: str, b_str: str, c_str: str) -> bool:
    a = int(a_str)
    b = int(b_str)
    c = int(c_str)
    if op == '+':
        return a + b == c
    elif op == '-':
        return a - b == c
    elif op == '*':
        return a * b == c
    return False

def parse_expression(expression: str):
    eq_pos = expression.find('=')
    if eq_pos == -1:
        return None
    left = expression[:eq_pos]
    c_str = expression[eq_pos + 1:]
    i = 0
    if i < len(left) and left[i] == '-':
        i += 1
    j = i
    while j < len(left) and left[j] in '0123456789?':
        j += 1
    if j == len(left) or left[j] not in '+-*':
        return None
    a_str = left[:j]
    op = left[j]
    b_str = left[j + 1:]
    return a_str, op, b_str, c_str

def solve_rune(expression: str) -> int:
    parts = parse_expression(expression)
    if not parts:
        return -1
    A_str, op, B_str, C_str = parts
    if '?' not in expression:
        return -1
    forbidden = set()
    for c in expression:
        if c.isdigit():
            forbidden.add(int(c))
    for d in range(10):
        if d in forbidden:
            continue
        A_new = A_str.replace('?', str(d))
        B_new = B_str.replace('?', str(d))
        C_new = C_str.replace('?', str(d))
        if (is_valid_number(A_new) and
            is_valid_number(B_new) and
            is_valid_number(C_new)):
            if check_equation(A_new, op, B_new, C_new):
                return d
    return -1

expression = input().strip()
print(solve_rune(expression))

