import math
import sys

def digit_to_char(d: int) -> str:
    if d < 10:
        return str(d)
    return chr(ord('A') + d - 10)

def converter(n: float, decimals: int = 0, base: float = math.pi) -> str:
    sign = '-' if n < 0 else ''
    abs_n = abs(n)
    remain = abs_n
    if abs_n < 1.0:
        int_str = '0'
    else:
        logb_absn = math.log(abs_n) / math.log(base)
        k = math.floor(logb_absn)
        # Refine k upwards
        while k < 10000:
            try:
                if math.pow(base, k + 1) > abs_n + 1e-10:
                    break
                k += 1
            except (OverflowError, ValueError):
                break
        # Refine k downwards
        while k >= 0:
            try:
                if math.pow(base, k) <= abs_n * 2:
                    break
                k -= 1
            except (OverflowError, ValueError):
                k -= 1
                continue
        int_digits = []
        for i in range(k, -1, -1):
            try:
                power = math.pow(base, i)
            except (OverflowError, ValueError):
                power = float('inf')
            digit = min(math.floor(remain / power), 35)
            int_digits.append(digit)
            remain -= digit * power
        int_str = ''.join(digit_to_char(d) for d in int_digits).lstrip('0') or '0'
    # Fractional part
    frac_digits = []
    frac_remain = remain
    for _ in range(decimals):
        frac_remain *= base
        digit = min(math.floor(frac_remain), 35)
        frac_digits.append(digit)
        frac_remain -= digit
    frac_str = ''.join(digit_to_char(d) for d in frac_digits)
    # Assemble
    if decimals == 0:
        result = int_str
    else:
        if int_str == '0':
            result = '0.' + frac_str
        else:
            result = int_str + '.' + frac_str
    # Check if zero
    is_zero = (int_str == '0' and all(d == 0 for d in frac_digits))
    if is_zero:
        if decimals == 0:
            return '0'
        else:
            return '0.' + '0' * decimals
    else:
        return sign + result

