def floor_sqrt(x):
    if x == 0 or x == 1:
        return x
    left = 1
    right = x // 2 + 1
    while left <= right:
        mid = left + (right - left) // 2
        mid_sq = mid * mid
        if mid_sq == x:
            return mid
        if mid_sq < x:
            left = mid + 1
        else:
            right = mid - 1
    return right

def is_perfect_square(x):
    if x < 0:
        return False
    s = floor_sqrt(x)
    return s * s == x

n = int(input().strip())
s = floor_sqrt(n)
if s * s == n:
    print(1)
else:
    # Check for 2 squares
    max_i = floor_sqrt(n // 2) + 1
    is_two = False
    for i in range(1, max_i + 1):
        rem = n - i * i
        if is_perfect_square(rem):
            is_two = True
            break
    if is_two:
        print(2)
    else:
        # Check 3/4 via Legendre's three-square theorem
        m = n
        while m % 4 == 0:
            m //= 4
        if m % 8 != 7:
