def countSubsequences(needle: str, haystack: str) -> int:
    m = len(needle)
    n = len(haystack)
    if m == 0:
        return 1
    MOD = 100000000
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    for i in range(n + 1):
        dp[i][0] = 1
    for j in range(1, m + 1):
        dp[0][j] = 0
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            dp[i][j] = dp[i - 1][j]
            if haystack[i - 1] == needle[j - 1]:
                dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD
    return dp[n][m]

