import sys

def prime_factors(n):
    if n <= 1:
        return []
    factors = []
    # Handle 2
    if n % 2 == 0:
        factors.append(2)
        while n % 2 == 0:
            n //= 2
    # Odd factors
    i = 3
    while i * i <= n:
        if n % i == 0:
            factors.append(i)
            while n % i == 0:
                n //= i
        i += 2
    # Remaining prime
    if n > 1:
        factors.append(n)
    return factors

def proper_fractions(n):
    if n <= 1:
        return 0
    primes = prime_factors(n)
    result = n
    for p in primes:
        result = (result // p) * (p - 1)
    return result

