                else:
                    rolls.append(parse_roll(third_char))
            return rolls
        else:
            return [parse_roll(char) for char in token]

    rolls = []
    for frame in frames:
        rolls.extend(parse_frame(frame))

    score = 0
    i = 0
    for _ in range(10):
        if i >= len(rolls):
