def get_canonical(s):
    res = []
    i = 0
    while i < len(s):
        if s[i] in 'ou':
            j = i
            while j < len(s) and s[j] in 'ou':
                j += 1
            W = 0
            for k in range(i, j):
                W += 1 if s[k] == 'o' else 2
            res.append('o' * W)
            i = j
        elif s[i] in 'kh':
            j = i
            while j < len(s) and s[j] in 'kh':
                j += 1
            run = s[i:j]
            num_h = run.count('h')
            if num_h == 0:
                res.append(run)
            else:
                last_h_idx = max(idx for idx, c in enumerate(run) if c == 'h')
                trailing = len(run) - last_h_idx - 1
                res.append('h' * num_h + 'k' * trailing)
            i = j
        else:
            res.append(s[i])
            i += 1
    return ''.join(res)

