def update_max(node, start, end, idx, val):
    if start == end:
        tree_max[node] = val
        return
    mid = (start + end) // 2
    if idx <= mid:
        update_max(2 * node, start, mid, idx, val)
    else:
        update_max(2 * node + 1, mid + 1, end, idx, val)
    tree_max[node] = max(tree_max[2 * node], tree_max[2 * node + 1])

def query_max(node, start, end, l, r):
    if r < start or end < l:
        return 0
    if l <= start and end <= r:
        return tree_max[node]
    mid = (start + end) // 2
    return max(query_max(2 * node, start, mid, l, r), query_max(2 * node + 1, mid + 1, end, l, r))

def update_min(node, start, end, idx, val):
    if start == end:
        tree_min[node] = val
        return
    mid = (start + end) // 2
    if idx <= mid:
        update_min(2 * node, start, mid, idx, val)
    else:
        update_min(2 * node + 1, mid + 1, end, idx, val)
    tree_min[node] = min(tree_min[2 * node], tree_min[2 * node + 1])

def query_min(node, start, end, l, r):
