def mul(a, b):
    res = [0.0] * (len(a) + len(b) - 1)
    for i in range(len(a)):
        for j in range(len(b)):
            res[i + j] += a[i] * b[j]
    return res

def compute_psi(u, p, adj, x):
    contribs = []
    for v in adj[u]:
        if v != p:
            psi_child = compute_psi(v, u, adj, x)
            d = len(psi_child) - 1
            q = [0.0] * (d + 2)
            s = 0.0
            for k in range(d + 1):
                s += psi_child[k] / (k + 1.0)
            q[0] = s
            for l in range(1, d + 2):
                k = l - 1
                if k < len(psi_child):
                    q[l] = -psi_child[k] / float(l)
            dd = max(len(psi_child) + 1, len(q))
            contrib = [0.0] * (dd + 1)
            for i in range(len(psi_child)):
                contrib[i + 1] += psi_child[i]
            for i in range(len(q)):
                if i < len(contrib):
                    contrib[i] += x * q[i]
            while len(contrib) > 1 and abs(contrib[-1]) < 1e-14:
                contrib.pop()
            contribs.append(contrib)
    if not contribs:
        return [1.0]
    psi = [1.0]
    for c in contribs:
        psi = mul(psi, c)
    while len(psi) > 1 and abs(psi[-1]) < 1e-14:
        psi.pop()
    return psi

